# Chercher les infos clients Notion pour Anne Salzer, Gilles Tobiala, Art Royal, VL Medical, Clément Delpiano
curl -s -H "Authorization: Bearer $(cat /home/gilles/.openclaw/credentials/notion)" -H "Notion-Version: 2022-06-28" -H "Content-Type: application/json" "https://api.notion.com/v1/databases/304ddac9-bdfc-8101-b72f-df250da9f1f6/query" -X POST -d '{}' | python3 -c "
import sys, json
data = json.load(sys.stdin)
for r in data.get('results', []):
    p = r['properties']
    # Get title
    titre = '?'
    for k, v in p.items():
        if v.get('type') == 'title' and v.get('title'):
            titre = v['title'][0].get('plain_text', '?') if v['title'] else '?'
    # Get email
    email = ''
    for k, v in p.items():
        if v.get('type') == 'email':
            email = v.get('email', '') or ''
    # Get status
    status = ''
    for k, v in p.items():
        if v.get('type') == 'select' and k.lower() in ['statut', 'status', 'abonnement']:
            sel = v.get('select')
            if sel:
                status += f'{k}={sel.get(\"name\",\"\")} '
    print(f'{titre} | {email} | {status.strip()}')
print(f'--- Total: {len(data.get(\"results\",[]))} clients')
" 2>&1 | head -50

# Check suivi paiements pour Art Royal
curl -s -H "Authorization: Bearer $(cat /home/gilles/.openclaw/credentials/notion)" -H "Notion-Version: 2022-06-28" -H "Content-Type: application/json" "https://api.notion.com/v1/databases/30cddac9-bdfc-8120-ba6c-c2f6c5ff726f/query" -X POST -d '{}' | python3 -c "
import sys, json
data = json.load(sys.stdin)
for r in data.get('results', []):
    p = r['properties']
    titre = '?'
    for k, v in p.items():
        if v.get('type') == 'title' and v.get('title'):
            titre = v['title'][0].get('plain_text', '?') if v['title'] else '?'
    montant = ''
    statut = ''
    for k, v in p.items():
        if v.get('type') == 'number':
            montant = f'{k}={v.get(\"number\",\"\")} '
        if v.get('type') == 'select':
            sel = v.get('select')
            if sel:
                statut += f'{k}={sel.get(\"name\",\"\")} '
    print(f'{titre} | {montant} | {statut}')
print(f'--- Total: {len(data.get(\"results\",[]))} paiements')
" 2>&1

